import React, { useState, useEffect, useCallback } from "react";
import { useDropzone } from "react-dropzone";
import { getHealth, runDetection, runEnhance, downloadPDF, runVideoDetection } from "./api";
import "./App.css";

/* ─── Tabs ───────────────────────────────────────────────────────────── */
const TABS = [
  { id: "scan", label: "🔬 Infrastructure Scan" },
  { id: "hull", label: "🚢 Hull Inspection" },
  { id: "video", label: "📹 Video Analysis" },
  { id: "pipeline", label: "🔩 Pipeline & Subsea" },
  { id: "cable", label: "⚡ Cable Anomaly" },
  { id: "dashboard", label: "📊 Mission Dashboard" },
  { id: "roadmap", label: "🗺️ Roadmap" },
];

/* ─── Severity badge ─────────────────────────────────────────────────── */
function SevBadge({ sev }) {
  const cls = { Critical: "sev-critical", High: "sev-high", Medium: "sev-medium", Low: "sev-low" }[sev] || "sev-medium";
  return <span className={`sev-badge ${cls}`}>{sev}</span>;
}

/* ─── Metric card ────────────────────────────────────────────────────── */
function Metric({ label, value }) {
  return (
    <div className="metric-card">
      <div className="metric-label">{label}</div>
      <div className="metric-value">{value}</div>
    </div>
  );
}

/* ─── Drop zone ──────────────────────────────────────────────────────── */
function FileDropzone({ onFile, accept, label }) {
  const onDrop = useCallback((files) => { if (files.length) onFile(files[0]); }, [onFile]);
  const { getRootProps, getInputProps, isDragActive } = useDropzone({ onDrop, accept, multiple: false });
  return (
    <div {...getRootProps()} className={`dropzone ${isDragActive ? "active" : ""}`}>
      <input {...getInputProps()} />
      <p style={{ fontSize: 28 }}>📁</p>
      <p>{label || "Drop image here or click to browse"}</p>
      <p style={{ fontSize: 11, color: "var(--muted2)" }}>JPG, PNG, WebP</p>
    </div>
  );
}

/* ─── Section Header ─────────────────────────────────────────────────── */
function SectionHeader({ crumb, title, subtitle }) {
  return (
    <div className="section-header">
      <div className="section-crumb">{crumb}</div>
      <div className="section-title">{title}</div>
      <div className="section-subtitle">{subtitle}</div>
    </div>
  );
}

/* ─── Results table ──────────────────────────────────────────────────── */
function DetectionTable({ dets }) {
  if (!dets || !dets.length) return null;
  return (
    <table className="det-table">
      <thead>
        <tr><th>#</th><th>Class</th><th>Severity</th><th>Confidence</th><th>Bounding Box</th><th>Area (px²)</th></tr>
      </thead>
      <tbody>
        {dets.map((d) => (
          <tr key={d.id}>
            <td>{String(d.id).padStart(2, "0")}</td>
            <td style={{ fontWeight: 700 }}>{d.cls}</td>
            <td><SevBadge sev={d.severity} /></td>
            <td>{(d.conf * 100).toFixed(1)}%</td>
            <td>({d.x1},{d.y1})→({d.x2},{d.y2})</td>
            <td>{(d.area || 0).toLocaleString()}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

/* ─── Risk Score Bar ─────────────────────────────────────────────────── */
function RiskBar({ risk, grade }) {
  const msg = grade === "D" ? "Critical — Immediate action required"
    : grade === "C" ? "High Risk — Maintenance within 7 days"
    : grade === "B" ? "Moderate Risk"
    : "Healthy";
  return (
    <div className="nc-card">
      <div style={{ fontSize: 11, color: "var(--muted2)", fontFamily: "JetBrains Mono, monospace", letterSpacing: 1, marginBottom: 4 }}>
        Structural Integrity Risk Score
      </div>
      <div style={{ display: "flex", alignItems: "baseline", gap: 12, marginBottom: 12 }}>
        <span style={{ fontSize: 34, fontWeight: 900, color: "#fbbf24", fontFamily: "JetBrains Mono, monospace" }}>
          {risk}<span style={{ fontSize: 15, color: "var(--muted2)" }}>/100</span>
        </span>
        <span style={{ fontSize: 15, fontWeight: 800 }}>Grade {grade} — {msg}</span>
      </div>
      <div className="risk-bar-track">
        <div className="risk-bar-fill" style={{ width: `${risk}%` }}></div>
      </div>
      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 8, fontSize: 10 }}>
        <span style={{ color: "#34d399" }}>Healthy 76–100</span>
        <span style={{ color: "#4cc9ff" }}>Moderate 51–75</span>
        <span style={{ color: "#fbbf24" }}>High Risk 26–50</span>
        <span style={{ color: "#f87171" }}>Critical 0–25</span>
      </div>
    </div>
  );
}


/* ═══════════════════════════════════════════════════════════════════════
   MAIN APP
   ═══════════════════════════════════════════════════════════════════════ */
export default function App() {
  const [tab, setTab] = useState("scan");
  const [health, setHealth] = useState(null);

  // Sidebar settings
  const [confThr, setConfThr] = useState(0.25);
  const [iouThr, setIouThr] = useState(0.45);
  const [sevFilter, setSevFilter] = useState("All Detections");
  const [useClahe, setUseClahe] = useState(true);
  const [claheClip, setClaheClip] = useState(3.0);
  const [useGreen, setUseGreen] = useState(true);
  const [useEdge, setUseEdge] = useState(false);
  const [turbidity, setTurbidity] = useState(0.0);
  const [corrTurb, setCorrTurb] = useState(true);
  const [marineSnow, setMarineSnow] = useState(false);
  const [vesselName, setVesselName] = useState("");
  const [inspector, setInspector] = useState("NautiCAI AutoScan v1.0");
  const [scanMode, setScanMode] = useState("hull");

  // State for each tab
  const [scanFile, setScanFile] = useState(null);
  const [scanPreview, setScanPreview] = useState(null);
  const [scanResult, setScanResult] = useState(null);
  const [scanLoading, setScanLoading] = useState(false);

  const [hullFile, setHullFile] = useState(null);
  const [hullPreview, setHullPreview] = useState(null);
  const [hullResult, setHullResult] = useState(null);
  const [hullEnhance, setHullEnhance] = useState(null);
  const [hullLoading, setHullLoading] = useState(false);

  const [pipeFile, setPipeFile] = useState(null);
  const [pipePreview, setPipePreview] = useState(null);
  const [pipeResult, setPipeResult] = useState(null);
  const [pipeLoading, setPipeLoading] = useState(false);

  const [cableFile, setCableFile] = useState(null);
  const [cablePreview, setCablePreview] = useState(null);
  const [cableResult, setCableResult] = useState(null);
  const [cableLoading, setCableLoading] = useState(false);

  const [videoFile, setVideoFile] = useState(null);
  const [videoResult, setVideoResult] = useState(null);
  const [videoLoading, setVideoLoading] = useState(false);

  const [missions, setMissions] = useState([]);
  const [pdfLoading, setPdfLoading] = useState(false);

  // Health check
  useEffect(() => { getHealth().then(setHealth).catch(() => setHealth({ status: "error", model: "N/A" })); }, []);

  const visParams = { use_clahe: useClahe, clahe_clip: claheClip, use_green: useGreen, use_edge: useEdge, turbidity_in: turbidity, corr_turb: corrTurb, marine_snow: marineSnow };
  const detParams = { conf_thr: confThr, iou_thr: iouThr, sev_filter: sevFilter, ...visParams };

  const addMission = (res, mode) => {
    setMissions(prev => [...prev, { id: res.mission_id, vessel: vesselName || "Unknown",
      date: res.scan_time, score: res.risk_score, grade: res.grade, detections: res.total, mode }]);
  };

  // File change handlers (preview)
  const handleScanFile = (f) => { setScanFile(f); setScanPreview(URL.createObjectURL(f)); setScanResult(null); };
  const handleHullFile = (f) => { setHullFile(f); setHullPreview(URL.createObjectURL(f)); setHullResult(null); setHullEnhance(null); };
  const handlePipeFile = (f) => { setPipeFile(f); setPipePreview(URL.createObjectURL(f)); setPipeResult(null); };
  const handleCableFile = (f) => { setCableFile(f); setCablePreview(URL.createObjectURL(f)); setCableResult(null); };

  /* ─── Detection runner helpers ─────────────────────────────────────── */
  const doDetect = async (file, mode, setResult, setLoading) => {
    setLoading(true);
    try {
      const res = await runDetection(file, { ...detParams, mode });
      setResult(res);
      addMission(res, mode);
    } catch (e) { alert("Detection error: " + (e.response?.data?.detail || e.message)); }
    setLoading(false);
  };

  const doPDF = async (file, mode) => {
    setPdfLoading(true);
    try { await downloadPDF(file, { ...detParams, mode, vessel_name: vesselName, inspector }); }
    catch (e) { alert("PDF error: " + (e.response?.data?.detail || e.message)); }
    setPdfLoading(false);
  };

  /* ═══════════════════════════════════════════════════════════════════
     RENDER
     ═══════════════════════════════════════════════════════════════════ */
  return (
    <div className="app-container">
      {/* ── SIDEBAR ────────────────────────────────────────────────── */}
      <aside className="sidebar">
        <div className="nc-card" style={{ padding: 12 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
            <div className="nc-logo" style={{ width: 34, height: 34, fontSize: 16 }}>🌊</div>
            <div>
              <div className="nc-title" style={{ fontSize: 13 }}>CONTROL CENTER</div>
              <div className="nc-sub">Detection + visibility tuning</div>
            </div>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <span className="nc-pill"><span className="nc-dot"></span> {health?.status === "ok" ? "Connected" : "Offline"}</span>
            <span className="nc-pill">v1.0.4</span>
          </div>
        </div>

        {health?.model && (
          <div className="status-info success" style={{ fontSize: 12 }}>🧠 {health.model} · Active</div>
        )}

        <div className="sidebar-section">
          <h4>Detection Engine</h4>
          <div className="control-group">
            <label className="control-label">Confidence Threshold: {confThr.toFixed(2)}</label>
            <input type="range" className="control-slider" min="0.05" max="0.95" step="0.05"
              value={confThr} onChange={e => setConfThr(+e.target.value)} />
          </div>
          <div className="control-group">
            <label className="control-label">IoU Threshold: {iouThr.toFixed(2)}</label>
            <input type="range" className="control-slider" min="0.10" max="0.90" step="0.05"
              value={iouThr} onChange={e => setIouThr(+e.target.value)} />
          </div>
        </div>

        <div className="sidebar-divider" />

        <div className="sidebar-section">
          <h4>Severity Filter</h4>
          <select className="control-select" value={sevFilter} onChange={e => setSevFilter(e.target.value)}>
            <option>All Detections</option><option>Critical Only</option><option>High+</option><option>Medium+</option>
          </select>
        </div>

        <div className="sidebar-divider" />

        <div className="sidebar-section">
          <h4>Visibility Engine</h4>
          <label className="control-toggle"><input type="checkbox" checked={useClahe} onChange={e => setUseClahe(e.target.checked)} /><span>CLAHE Enhancement</span></label>
          <div className="control-group" style={{marginLeft: 24}}>
            <label className="control-label">CLAHE Clip: {claheClip.toFixed(1)}</label>
            <input type="range" className="control-slider" min="1" max="8" step="0.5" value={claheClip} onChange={e => setClaheClip(+e.target.value)} />
          </div>
          <label className="control-toggle"><input type="checkbox" checked={useGreen} onChange={e => setUseGreen(e.target.checked)} /><span>Green-Water Filter</span></label>
          <label className="control-toggle"><input type="checkbox" checked={useEdge} onChange={e => setUseEdge(e.target.checked)} /><span>Edge Estimator</span></label>
          <div className="control-group">
            <label className="control-label">Turbidity: {turbidity.toFixed(2)}</label>
            <input type="range" className="control-slider" min="0" max="1" step="0.05" value={turbidity} onChange={e => setTurbidity(+e.target.value)} />
          </div>
          <label className="control-toggle"><input type="checkbox" checked={corrTurb} onChange={e => setCorrTurb(e.target.checked)} /><span>Turbidity Correction</span></label>
          <label className="control-toggle"><input type="checkbox" checked={marineSnow} onChange={e => setMarineSnow(e.target.checked)} /><span>Marine Snow</span></label>
        </div>

        <div className="sidebar-divider" />

        <div className="sidebar-section">
          <h4>Mission Info</h4>
          <div className="control-group">
            <label className="control-label">Vessel Name</label>
            <input className="control-input" placeholder="e.g. MV Neptune Star" value={vesselName} onChange={e => setVesselName(e.target.value)} />
          </div>
          <div className="control-group">
            <label className="control-label">Inspector</label>
            <input className="control-input" value={inspector} onChange={e => setInspector(e.target.value)} />
          </div>
          <div className="control-group">
            <label className="control-label">Inspection Mode</label>
            <select className="control-select" value={scanMode} onChange={e => setScanMode(e.target.value)}>
              <option value="hull">Hull Inspection</option>
              <option value="pipeline">Pipeline</option>
              <option value="cable">Subsea Cable</option>
              <option value="port">Port Infra</option>
              <option value="general">General</option>
            </select>
          </div>
        </div>
      </aside>

      {/* ── MAIN CONTENT ──────────────────────────────────────────── */}
      <main className="main-content">
        {/* Top bar */}
        <div className="nc-card">
          <div className="nc-topbar">
            <div className="nc-brand">
              <div className="nc-logo">🌊</div>
              <div>
                <div className="nc-title">NAUTICAI</div>
                <div className="nc-sub">Underwater Infrastructure Inspection Copilot</div>
              </div>
            </div>
            <div className="nc-pill">
              <span className="nc-dot"></span>
              <span style={{ fontFamily: "JetBrains Mono, monospace" }}>
                {health?.model ? `Model: ${health.model}` : "Connecting..."}
              </span>
            </div>
          </div>
        </div>

        {/* Tab navigation */}
        <div className="tab-list">
          {TABS.map(t => (
            <button key={t.id} className={`tab-btn ${tab === t.id ? "active" : ""}`} onClick={() => setTab(t.id)}>
              {t.label}
            </button>
          ))}
        </div>

        {/* ── INFRASTRUCTURE SCAN TAB ──────────────────────────────── */}
        {tab === "scan" && (
          <div>
            <SectionHeader crumb="NAUTICAI / INFRASTRUCTURE SCAN" title="Infrastructure Scan"
              subtitle="AI-powered underwater defect detection · YOLOv8 · 19 defect classes · annotated output + professional report" />
            <div className="nc-card">
              <div className="image-grid">
                <div>
                  <FileDropzone onFile={handleScanFile} accept={{ "image/*": [".jpg", ".jpeg", ".png", ".webp"] }} />
                  <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
                    <button className="btn-primary" disabled={!scanFile || scanLoading}
                      onClick={() => doDetect(scanFile, scanMode, setScanResult, setScanLoading)}>
                      {scanLoading ? <><span className="spinner" /> Running...</> : "Run AI Detection"}
                    </button>
                    <button className="btn-secondary" disabled={!scanFile || pdfLoading}
                      onClick={() => doPDF(scanFile, scanMode)}>
                      {pdfLoading ? "Generating..." : "📄 Download PDF"}
                    </button>
                  </div>
                </div>
                <div>{scanPreview && <img src={scanPreview} alt="Preview" />}</div>
              </div>
            </div>

            {scanResult && (
              <>
                <div className="metrics-row">
                  <Metric label="Total Detections" value={scanResult.total} />
                  <Metric label="Critical" value={scanResult.sev_counts.Critical} />
                  <Metric label="High" value={scanResult.sev_counts.High} />
                  <Metric label="Medium" value={scanResult.sev_counts.Medium} />
                  <Metric label="Risk Score" value={`${scanResult.risk_score}/100`} />
                  <Metric label="Grade" value={scanResult.grade} />
                </div>
                <div className="nc-card">
                  <div className="image-grid">
                    <div>
                      <p style={{fontSize:11, fontWeight:800, color:"var(--muted2)", letterSpacing:".8px", textTransform:"uppercase", marginBottom:8}}>Annotated Output</p>
                      <img src={`data:image/png;base64,${scanResult.annotated_b64}`} alt="Annotated" style={{width:"100%",borderRadius:12}} />
                    </div>
                    <div>
                      <p style={{fontSize:11, fontWeight:800, color:"var(--muted2)", letterSpacing:".8px", textTransform:"uppercase", marginBottom:8}}>Risk Heatmap</p>
                      <img src={`data:image/png;base64,${scanResult.heatmap_b64}`} alt="Heatmap" style={{width:"100%",borderRadius:12}} />
                    </div>
                  </div>
                </div>
                <RiskBar risk={scanResult.risk_score} grade={scanResult.grade} />
                <div className="nc-card">
                  <p style={{fontSize:11, fontWeight:800, color:"var(--muted2)", letterSpacing:".8px", textTransform:"uppercase", marginBottom:10}}>Detection Results</p>
                  <DetectionTable dets={scanResult.detections} />
                </div>
              </>
            )}
          </div>
        )}

        {/* ── HULL INSPECTION TAB ─────────────────────────────────── */}
        {tab === "hull" && (
          <div>
            <SectionHeader crumb="NAUTICAI / HULL INSPECTION" title="Hull Inspection"
              subtitle="Visibility enhancement pipeline — CLAHE · Green-Water · Turbidity · Edge Estimator" />
            <div className="nc-card">
              <div className="image-grid">
                <div>
                  <FileDropzone onFile={handleHullFile} accept={{ "image/*": [".jpg", ".jpeg", ".png"] }} />
                  <button className="btn-primary" style={{marginTop:10}} disabled={!hullFile || hullLoading}
                    onClick={async () => {
                      setHullLoading(true);
                      try {
                        const [enh, det] = await Promise.all([
                          runEnhance(hullFile, visParams),
                          runDetection(hullFile, { ...detParams, mode: "hull" }),
                        ]);
                        setHullEnhance(enh); setHullResult(det); addMission(det, "hull");
                      } catch(e) { alert(e.message); }
                      setHullLoading(false);
                    }}>
                    {hullLoading ? <><span className="spinner" /> Running...</> : "Run AI Detection"}
                  </button>
                </div>
                <div>{hullPreview && <img src={hullPreview} alt="Hull preview" />}</div>
              </div>
            </div>

            {hullEnhance && (
              <div className="nc-card">
                <p style={{fontSize:11, fontWeight:800, color:"var(--muted2)", letterSpacing:".8px", textTransform:"uppercase", marginBottom:10}}>Enhancement Comparison</p>
                <div className="image-grid-4">
                  <div><img src={`data:image/png;base64,${hullEnhance.clahe_b64}`} alt="CLAHE" /><p style={{textAlign:"center",fontSize:11,color:"var(--muted)",marginTop:4}}>CLAHE</p></div>
                  <div><img src={`data:image/png;base64,${hullEnhance.green_b64}`} alt="Green-Water" /><p style={{textAlign:"center",fontSize:11,color:"var(--muted)",marginTop:4}}>Green-Water</p></div>
                  <div><img src={`data:image/png;base64,${hullEnhance.turbidity_b64}`} alt="Turbidity" /><p style={{textAlign:"center",fontSize:11,color:"var(--muted)",marginTop:4}}>Turbidity Sim</p></div>
                  <div><img src={`data:image/png;base64,${hullEnhance.edge_b64}`} alt="Edge" /><p style={{textAlign:"center",fontSize:11,color:"var(--muted)",marginTop:4}}>Edge Estimator</p></div>
                </div>
              </div>
            )}

            {hullResult && (
              <>
                <div className="metrics-row">
                  <Metric label="Risk Score" value={`${hullResult.risk_score}/100`} />
                  <Metric label="Grade" value={hullResult.grade} />
                  <Metric label="Anomalies" value={hullResult.total} />
                </div>
                <div className="nc-card">
                  <div className="image-grid">
                    <img src={`data:image/png;base64,${hullResult.annotated_b64}`} alt="Annotated" />
                    <img src={`data:image/png;base64,${hullResult.heatmap_b64}`} alt="Heatmap" />
                  </div>
                </div>
                <div className="nc-card"><DetectionTable dets={hullResult.detections} /></div>
                <button className="btn-primary" style={{marginTop:8}} disabled={!hullFile || pdfLoading}
                  onClick={() => doPDF(hullFile, "hull")}>
                  {pdfLoading ? "Generating..." : "📄 Generate Hull Inspection PDF"}
                </button>
              </>
            )}
          </div>
        )}

        {/* ── VIDEO ANALYSIS TAB ──────────────────────────────────── */}
        {tab === "video" && (
          <div>
            <SectionHeader crumb="NAUTICAI / VIDEO ANALYSIS" title="Video Analysis"
              subtitle="Frame-by-frame defect detection · RTSP live stream support · v1.5 planned (Q2 2026)" />
            <div className="nc-card">
              <FileDropzone onFile={f => { setVideoFile(f); setVideoResult(null); }}
                accept={{ "video/*": [".mp4", ".avi", ".mov", ".mkv"] }}
                label="Drop underwater video here or click to browse" />
              <button className="btn-primary" style={{marginTop:10}} disabled={!videoFile || videoLoading}
                onClick={async () => {
                  setVideoLoading(true);
                  try {
                    const res = await runVideoDetection(videoFile, { ...detParams, mode: scanMode, sample_n: 10 });
                    setVideoResult(res);
                  } catch(e) { alert(e.message); }
                  setVideoLoading(false);
                }}>
                {videoLoading ? <><span className="spinner" /> Analysing Video...</> : "Analyse Video"}
              </button>
            </div>

            {videoResult && (
              <>
                <div className="metrics-row">
                  <Metric label="Total Frames" value={videoResult.video_info.total_frames} />
                  <Metric label="FPS" value={videoResult.video_info.fps} />
                  <Metric label="Resolution" value={videoResult.video_info.resolution} />
                  <Metric label="Duration" value={`${videoResult.video_info.duration}s`} />
                  <Metric label="Total Detections" value={videoResult.total_detections} />
                  <Metric label="Risk / Grade" value={`${videoResult.risk_score} / ${videoResult.grade}`} />
                </div>
                {videoResult.sample_frames?.length > 0 && (
                  <div className="nc-card">
                    <div className="image-grid-4">
                      {videoResult.sample_frames.map((f, i) => (
                        <div key={i}>
                          <img src={`data:image/png;base64,${f.annotated_b64}`} alt={`Frame ${f.frame_num}`} />
                          <p style={{textAlign:"center",fontSize:11,color:"var(--muted)",marginTop:4}}>Frame {f.frame_num} · {f.detection_count} det.</p>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </>
            )}
          </div>
        )}

        {/* ── PIPELINE TAB ────────────────────────────────────────── */}
        {tab === "pipeline" && (
          <div>
            <SectionHeader crumb="NAUTICAI / PIPELINE & SUBSEA" title="Pipeline Anomaly Detection"
              subtitle="7 pipeline-specific classes · Corrosion · Crack · Coating Failure · Pitting · Leakage · Weld Defect · Blockage" />
            <div className="nc-card">
              <div className="image-grid">
                <div>
                  <FileDropzone onFile={handlePipeFile} accept={{ "image/*": [".jpg", ".jpeg", ".png"] }} />
                  <button className="btn-primary" style={{marginTop:10}} disabled={!pipeFile || pipeLoading}
                    onClick={() => doDetect(pipeFile, "pipeline", setPipeResult, setPipeLoading)}>
                    {pipeLoading ? <><span className="spinner" /> Running...</> : "Run AI Detection"}
                  </button>
                </div>
                <div>{pipePreview && <img src={pipePreview} alt="Pipeline preview" />}</div>
              </div>
            </div>
            {pipeResult && (
              <>
                <div className="metrics-row">
                  <Metric label="Risk Score" value={`${pipeResult.risk_score}/100`} />
                  <Metric label="Grade" value={pipeResult.grade} />
                  <Metric label="Anomalies" value={pipeResult.total} />
                </div>
                <div className="nc-card">
                  <div className="image-grid">
                    <img src={`data:image/png;base64,${pipeResult.annotated_b64}`} alt="Annotated" />
                    <img src={`data:image/png;base64,${pipeResult.heatmap_b64}`} alt="Heatmap" />
                  </div>
                </div>
                <RiskBar risk={pipeResult.risk_score} grade={pipeResult.grade} />
                <div className="nc-card"><DetectionTable dets={pipeResult.detections} /></div>
                <button className="btn-primary" style={{marginTop:8}} disabled={!pipeFile || pdfLoading}
                  onClick={() => doPDF(pipeFile, "pipeline")}>
                  {pdfLoading ? "Generating..." : "📄 Generate Pipeline PDF"}
                </button>
              </>
            )}
          </div>
        )}

        {/* ── CABLE TAB ───────────────────────────────────────────── */}
        {tab === "cable" && (
          <div>
            <SectionHeader crumb="NAUTICAI / SUBSEA CABLE" title="Subsea Cable Anomaly Detection"
              subtitle="6 cable classes · Fracture · Deformation · Foreign Object · Biofouling · Marine Growth · Dent" />
            <div className="nc-card">
              <FileDropzone onFile={handleCableFile} accept={{ "image/*": [".jpg", ".jpeg", ".png"] }} />
              <button className="btn-primary" style={{marginTop:10}} disabled={!cableFile || cableLoading}
                onClick={() => doDetect(cableFile, "cable", setCableResult, setCableLoading)}>
                {cableLoading ? <><span className="spinner" /> Running...</> : "Run AI Detection"}
              </button>
            </div>
            {cableResult && (
              <>
                <div className="metrics-row">
                  <Metric label="Risk Score" value={`${cableResult.risk_score}/100`} />
                  <Metric label="Grade" value={cableResult.grade} />
                  <Metric label="Anomalies" value={cableResult.total} />
                </div>
                <div className="nc-card">
                  <div className="image-grid">
                    <img src={`data:image/png;base64,${cableResult.annotated_b64}`} alt="Annotated" />
                    <img src={`data:image/png;base64,${cableResult.heatmap_b64}`} alt="Heatmap" />
                  </div>
                </div>
                <div className="nc-card"><DetectionTable dets={cableResult.detections} /></div>
                <button className="btn-primary" style={{marginTop:8}} disabled={!cableFile || pdfLoading}
                  onClick={() => doPDF(cableFile, "cable")}>
                  {pdfLoading ? "Generating..." : "📄 Generate Cable PDF"}
                </button>
              </>
            )}
          </div>
        )}

        {/* ── DASHBOARD TAB ───────────────────────────────────────── */}
        {tab === "dashboard" && (
          <div>
            <SectionHeader crumb="NAUTICAI / MISSION DASHBOARD" title="Mission Dashboard"
              subtitle="Fleet overview · mission history · risk trend · model performance analytics" />
            {missions.length === 0 ? (
              <div className="status-info warning">No missions yet — run a scan on the Infrastructure Scan tab.</div>
            ) : (
              <>
                <div className="metrics-row">
                  <Metric label="Total Missions" value={missions.length} />
                  <Metric label="Avg Risk Score" value={`${Math.round(missions.reduce((s, m) => s + m.score, 0) / missions.length)}/100`} />
                  <Metric label="Total Detections" value={missions.reduce((s, m) => s + m.detections, 0)} />
                  <Metric label="Critical Missions" value={missions.filter(m => m.grade === "D").length} />
                </div>
                <div className="nc-card">
                  <table className="det-table">
                    <thead><tr><th>Mission ID</th><th>Vessel</th><th>Date</th><th>Score</th><th>Grade</th><th>Detections</th><th>Mode</th></tr></thead>
                    <tbody>
                      {missions.map((m, i) => (
                        <tr key={i}><td>{m.id}</td><td>{m.vessel}</td><td>{m.date}</td><td>{m.score}/100</td><td>{m.grade}</td><td>{m.detections}</td><td>{m.mode}</td></tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </>
            )}
            <div className="nc-card" style={{marginTop: 12}}>
              <p style={{fontSize:11, fontWeight:800, color:"var(--muted2)", letterSpacing:".8px", textTransform:"uppercase", marginBottom:10}}>Model Performance Metrics — YOLOv8s</p>
              <div className="metrics-row">
                <Metric label="Precision" value="94.2%" />
                <Metric label="Recall" value="89.1%" />
                <Metric label="mAP@0.5" value="91.4%" />
                <Metric label="mAP@0.5:0.95" value="78.3%" />
                <Metric label="F1 Score" value="91.6%" />
              </div>
            </div>
          </div>
        )}

        {/* ── ROADMAP TAB ─────────────────────────────────────────── */}
        {tab === "roadmap" && (
          <div>
            <SectionHeader crumb="NAUTICAI / ROADMAP" title="Technology Roadmap"
              subtitle="30+ features across v1.0 · v1.5 · v2.0 — built for subsea operators, ROV/AUV teams, and inspection companies" />
            <div className="nc-card">
              <div style={{display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:12}}>
                {[
                  {phase:"v1.0", total:24, live:24, eta:"Feb 2026", color:"#34d399"},
                  {phase:"v1.5", total:4, live:0, eta:"Q2 2026", color:"#4cc9ff"},
                  {phase:"v2.0", total:2, live:0, eta:"Q4 2026", color:"#a78bfa"},
                ].map(p => (
                  <div key={p.phase} style={{background:"rgba(255,255,255,0.04)", border:"1px solid var(--stroke2)", borderRadius:16, padding:16}}>
                    <div style={{display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10}}>
                      <span style={{fontSize:18, fontWeight:900, color:p.color, fontFamily:"JetBrains Mono,monospace"}}>{p.phase}</span>
                      <span style={{fontSize:10, fontWeight:900, letterSpacing:1, padding:"4px 10px", borderRadius:999,
                        background: p.live > 0 ? "rgba(52,211,153,.12)" : "rgba(148,163,184,.10)",
                        color: p.live > 0 ? "#34d399" : "var(--muted2)",
                        border: `1px solid ${p.live > 0 ? "rgba(52,211,153,.25)" : "rgba(148,163,184,.14)"}`
                      }}>{p.live > 0 ? "LIVE" : "PLANNED"}</span>
                    </div>
                    <div style={{fontSize:30, fontWeight:900, fontFamily:"JetBrains Mono,monospace"}}>
                      {p.live}<span style={{fontSize:16, color:"var(--muted2)"}}>/{p.total}</span>
                    </div>
                    <div style={{fontSize:10, color:"var(--muted2)", letterSpacing:".8px", textTransform:"uppercase", marginBottom:8}}>
                      FEATURES ACTIVE · ETA {p.eta}
                    </div>
                    <div className="risk-bar-track">
                      <div style={{width:`${p.total>0?Math.round(p.live/p.total*100):0}%`, height:"100%", borderRadius:999, background:p.color}}></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Footer */}
        <div className="footer">
          NautiCAI · Singapore Maritime AI Systems · Est. 2024 · v1.0.4 ·
          YOLOv8 · OpenCV · React · FastAPI · NVIDIA Jetson Orin
        </div>
      </main>
    </div>
  );
}
